import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { useParams, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import { updateCourse, deleteCourse } from "../courseReducer";

function EditCourse() {
  const { id } = useParams();
  const courseId = parseInt(id); // Преобразуем id в число
  const [name, setName] = useState("");
  const [subjectId, setSubjectId] = useState("");
  const [classId, setClassId] = useState("");
  const [deadline, setDeadline] = useState("");
  const [file, setFile] = useState(null);
  const [existingFiles, setExistingFiles] = useState([]);
  const [course, setCourse] = useState(null);
  const [subjects, setSubjects] = useState([]);
  const [classes, setClasses] = useState([]);
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  useEffect(() => {
    if (!courseId || isNaN(courseId)) {
      toast.error("Некорректный ID курса");
      navigate("/courses");
      return;
    }

    const fetchData = async () => {
      try {
        const [courseRes, filesRes, teacherSubjectsRes, classesRes] = await Promise.all([
          fetch(`http://localhost:3001/courses/${courseId}`),
          fetch(`http://localhost:3001/files?courseId=${courseId}`),
          fetch(`http://localhost:3001/teacher_subjects?teacherId=${user.id}`),
          fetch(`http://localhost:3001/classes`),
        ]);

        // Проверка ответа для курса
        if (!courseRes.ok) throw new Error(`Не удалось загрузить курс: ${courseRes.status}`);
        const courseData = await courseRes.json();
        if (!courseData || !courseData.name || !courseData.id) {
          throw new Error("Некорректные данные курса");
        }
        console.log("Fetched course:", courseData);
        setCourse(courseData);
        setName(courseData.name);
        setSubjectId(courseData.subjectId);
        setClassId(courseData.classId);
        setDeadline(courseData.deadline);

        // Проверка ответа для файлов
        if (!filesRes.ok) throw new Error(`Не удалось загрузить файлы: ${filesRes.status}`);
        const filesData = await filesRes.json();
        if (!Array.isArray(filesData)) throw new Error("Некорректные данные файлов");
        console.log("Fetched files:", filesData);
        setExistingFiles(filesData);

        // Проверка ответа для предметов
        if (!teacherSubjectsRes.ok) throw new Error(`Не удалось загрузить предметы учителя: ${teacherSubjectsRes.status}`);
        const teacherSubjectsData = await teacherSubjectsRes.json();
        if (!Array.isArray(teacherSubjectsData)) throw new Error("Некорректные данные предметов учителя");
        const subjectIds = teacherSubjectsData.map((ts) => ts.subjectId);
        if (!subjectIds.length) {
          toast.warn("Предметы не найдены");
          setSubjects([]);
        } else {
          const subjectsRes = await fetch(`http://localhost:3001/subjects?id=${subjectIds.join("&id=")}`);
          if (!subjectsRes.ok) throw new Error(`Не удалось загрузить предметы: ${subjectsRes.status}`);
          const subjectsData = await subjectsRes.json();
          if (!Array.isArray(subjectsData)) throw new Error("Некорректные данные предметов");
          console.log("Fetched subjects:", subjectsData);
          setSubjects(subjectsData);
          if (!subjectsData.length) toast.warn("Предметы не найдены");
        }

        // Проверка ответа для классов
        if (!classesRes.ok) throw new Error(`Не удалось загрузить классы: ${classesRes.status}`);
        const classesData = await classesRes.json();
        if (!Array.isArray(classesData)) throw new Error("Некорректные данные классов");
        console.log("Fetched classes:", classesData);
        setClasses(classesData);
        if (!classesData.length) toast.warn("Классы не найдены");
      } catch (error) {
        console.error("Error fetching data:", error);
        toast.error(error.message || "Ошибка загрузки данных");
      }
    };

    fetchData();
  }, [courseId, user.id, navigate]);

  async function handleSubmit(e) {
    e.preventDefault();
    let filePath = null;

    if (file) {
      const allowedTypes = ["image/jpeg", "image/png", "application/pdf"];
      const maxSize = 5 * 1024 * 1024;

      if (!allowedTypes.includes(file.type)) {
        toast.error("Допустимы только изображения (JPEG, PNG) или PDF-файлы");
        return;
      }

      if (file.size > maxSize) {
        toast.error("Файл слишком большой. Максимальный размер: 5 МБ");
        return;
      }

      const formData = new FormData();
      formData.append("file", file);
      try {
        const response = await fetch("http://localhost:3002/upload", {
          method: "POST",
          body: formData,
        });
        if (!response.ok) throw new Error(`Не удалось загрузить файл: ${response.status}`);
        const data = await response.json();
        if (!data.filePath) throw new Error("Некорректный путь файла");
        filePath = data.filePath;
      } catch (error) {
        console.error("File upload error:", error);
        toast.error(error.message || "Сетевая ошибка при загрузке файла");
        return;
      }
    }

    try {
      const updatedCourse = {
        id: courseId,
        name,
        subjectId: parseInt(subjectId),
        classId: parseInt(classId),
        teacherId: parseInt(user.id),
        deadline,
      };
      console.log("Updating course with data:", updatedCourse);
      const response = await fetch(`http://localhost:3001/courses/${courseId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(updatedCourse),
      });

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(errorText || `Не удалось обновить курс: ${response.status}`);
      }

      if (filePath) {
        const fileResponse = await fetch("http://localhost:3001/files", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            courseId: courseId,
            filePath,
            fileName: file.name,
          }),
        });
        if (!fileResponse.ok) throw new Error(`Не удалось сохранить файл: ${fileResponse.status}`);
      }
      dispatch(updateCourse(updatedCourse));
      toast.success("Курс успешно обновлен!");
      navigate("/courses");
    } catch (error) {
      console.error("Course update error:", error);
      toast.error(error.message || "Сетевая ошибка при обновлении курса");
    }
  }

  async function handleDelete() {
    console.log("Attempting to delete course with ID:", courseId);
    try {
      const response = await fetch(`http://localhost:3001/courses/${courseId}`, {
        method: "DELETE",
      });

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(errorText || `Не удалось удалить курс: ${response.status}`);
      }

      dispatch(deleteCourse(courseId));
      toast.success("Курс успешно удален!");
      navigate("/courses");
    } catch (error) {
      console.error("Delete error:", error);
      toast.error(error.message || "Сетевая ошибка при удалении курса");
    }
  }

  if (user?.role !== "teacher") {
    return <div className="container mt-5"><h1 className="title">Доступ запрещен</h1></div>;
  }

  if (course && parseInt(course.teacherId) !== parseInt(user.id)) {
    return (
      <div className="container mt-5">
        <h1 className="title">Вы не можете редактировать этот курс</h1>
      </div>
    );
  }

  return (
    <div className="container mt-5">
      <div className="row justify-content-center">
        <div className="col-md-8">
          <div className="card shadow">
            <div className="card-body">
              <h2 className="card-title text-center mb-4">Редактировать курс</h2>
              <form onSubmit={handleSubmit}>
                <div className="mb-3">
                  <label htmlFor="name" className="form-label">
                    Название курса
                  </label>
                  <input
                    type="text"
                    id="name"
                    className="form-control"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="subject" className="form-label">
                    Предмет
                  </label>
                  <select
                    id="subject"
                    className="form-select"
                    value={subjectId}
                    onChange={(e) => setSubjectId(e.target.value)}
                    required
                  >
                    <option value="">-- Выберите предмет --</option>
                    {subjects.map((subject) => (
                      <option key={subject.id} value={subject.id}>
                        {subject.name}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="mb-3">
                  <label htmlFor="class" className="form-label">
                    Класс
                  </label>
                  <select
                    id="class"
                    className="form-select"
                    value={classId}
                    onChange={(e) => setClassId(e.target.value)}
                    required
                  >
                    <option value="">-- Выберите класс --</option>
                    {classes.map((cls) => (
                      <option key={cls.id} value={cls.id}>
                        {cls.name}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="mb-3">
                  <label htmlFor="deadline" className="form-label">
                    Дедлайн курса
                  </label>
                  <input
                    type="date"
                    id="deadline"
                    className="form-control"
                    value={deadline}
                    onChange={(e) => setDeadline(e.target.value)}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="file" className="form-label">
                    Добавить новый файл (JPEG, PNG, PDF, до 5 МБ)
                  </label>
                  <input
                    type="file"
                    id="file"
                    className="form-control"
                    onChange={(e) => setFile(e.target.files[0])}
                  />
                </div>
                {existingFiles.length > 0 && (
                  <div className="mb-3">
                    <h5>Существующие файлы:</h5>
                    <ul className="list-group">
                      {existingFiles.map((f) => (
                        <li key={f.id} className="list-group-item">
                          <a href={`http://localhost:3002${f.filePath}`} download>
                            {f.fileName}
                          </a>
                        </li>
                      ))}
                    </ul>
                  </div>
                )}
                <div className="d-flex justify-content-between">
                  <button type="submit" className="btn btn-primary w-100 me-2">
                    Обновить
                  </button>
                  <button
                    type="button"
                    onClick={handleDelete}
                    className="btn btn-danger w-100"
                  >
                    Удалить курс
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default EditCourse;
